using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FileController : ControllerBase
    {
        private readonly string _uploadsFolder = @"C:\uploads";

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            var filePath = Path.Combine(_uploadsFolder, filename);

            if (!Path.IsPathRooted(filePath))
                filePath = Path.GetFullPath(filePath);

            if (string.IsNullOrEmpty(filename) || !File.Exists(filePath))
                return NotFound();

            var extension = Path.GetExtension(filename).ToLower();
            switch (extension)
            {
                case ".pdf":
                    return PhysicalFile(filePath, "application/pdf");
                case ".docx":
                case ".xlsx":
                case ".pptx":
                    return PhysicalFile(filePath, "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
                default:
                    var mimeType = MimeMapping.GetMimeMapping(extension);
                    if (string.IsNullOrEmpty(mimeType))
                        return NotFound();
                    return PhysicalFile(filePath, mimeType);
            }
        }
    }
